mapper.select:
select t.id, t.device_id, d.product_no as device_product_no, d.product_name as device_product_name, t.operator_id, u.real_name as operator_name, t.meter_point_id, t.test_date, case when exists(select 1 from biz_test_result r where r.task_id = t.id and r.is_pass = 0) then 0 else 1 end as result from biz_test_task t left join biz_device d on t.device_id = d.id left join sys_user u on t.operator_id = u.id
and t.id = #{taskId}
and d.product_no like concat('%', #{deviceProductNo}, '%')
and u.real_name like concat('%', #{operatorName}, '%')
and t.operator_id = #{operatorId}
and t.test_date >= #{startDate}
and t.test_date <= #{endDate}
and not exists(select 1 from biz_test_result r2 where r2.task_id = t.id and r2.is_pass = 0)
and exists(select 1 from biz_test_result r2 where r2.task_id = t.id and r2.is_pass = 0)
order by t.test_date desc, t.id desc limit #{offset}, #{size}

select count(1)
from biz_test_task t
         left join biz_device d on t.device_id = d.id
         left join sys_user u on t.operator_id = u.id


        and t.id = #{taskId}


        and d.product_no like concat('%', #{deviceProductNo}, '%')


        and u.real_name like concat('%', #{operatorName}, '%')


        and t.operator_id = #{operatorId}


        and t.test_date >= #{startDate}


        and t.test_date <= #{endDate}




                and not exists(select 1 from biz_test_result r2 where r2.task_id = t.id and r2.is_pass = 0)


                and exists(select 1 from biz_test_result r2 where r2.task_id = t.id and r2.is_pass = 0)
